var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>ARC-KS1</color>\\n번화가 멀티플렉스, ■년 전.","JPN":"<color=#ffd34c>ARC-KS1</color>\\n繁華街のマルチプレックス、■年前。","ENG":"<color=#ffd34c>ARC-KS1</color>\\nDowntown Multiplex. ■ years ago.","TWN":"<color=#ffd34c>ARC-KS1</color>\\n鬧區大型商場，■年前","THA":"<color=#ffd34c>ARC-KS1</color>\\nมัลติเพล็กซ์กลางเมือง ■ ปีก่อน","VTN":"<color=#ffd34c>ARC-KS1</color>\\nCụm Rạp Trung Tâm. ■ năm trước.","SCN":"<color=#ffd34c>ARC-KS1</color>\\n商业街多厅影院，■年前。","DEU":"<color=#ffd34c>ARC-KS1</color>\\nMultiplex in der Innenstadt. Vor ■ Jahren.","FRA":"<color=#ffd34c>ARC-KS1</color>\\nMultiplex du centre-ville, ■ ans plus tôt."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"제 아버지는 거의 완벽한 존재입니다.","JPN":"私の父はほぼ完璧な存在です。","ENG":"My Father is a near-perfect being.","TWN":"我的爸爸幾乎是零缺點般的完美。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"하지만 그 말을 역으로 생각하면, 결국 완벽하지 못한 존재라는 뜻이죠.","JPN":"ですがその言葉を逆にとれば、結局は完ぺきではない存在という意味です。","ENG":"However, if phrased differently, it implies that he is not perfect.","TWN":"但反過來說，也無法達到完美的意思吧。"},"stage":{"bg":"MS_1001","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"단 한 걸음.","JPN":"たった一歩。","ENG":"Always one step short.","TWN":"一步。"},"stage":{"bg":"MS_1001","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그 한 걸음이 부족했기에 아버지는 항상 모든 것을 잃어 왔습니다.","JPN":"その一歩が足りないせいで、父は常にすべてを失ってきました。","ENG":"He lost everything because he could not take that one extra step.","TWN":"就因為差那一步，爸爸總是在失去。"},"stage":{"bg":"MS_1001","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그래서 저는 아버지가 그 부족한 한 걸음을 내디딜 수 있도록 도와드리고 있습니다.","JPN":"ですから私は父がその足りない一歩を踏み出すことができるようにお手伝いしています。","ENG":"That is why I am assisting Father in taking the one step he is lacking.","TWN":"因此我總是在幫助爸爸可以達到那一步。"},"stage":{"bg":"MS_1001","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"아…… 네. 장한 따님, 아니 아드님이시군요.","JPN":"あ……はい。健気な娘さん、いや、息子さんですね。","ENG":"Oh... He's lucky to have you as his daugh– Oh, I mean, son.","TWN":"喔……好棒的女兒…不對，是好棒的兒子喔～"},"stage":{"bg":"MS_1001","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"그런데 그런 이야기를 왜 갑자기 저에게 와서 하시는 겁니까?","JPN":"ところで、どうしてそんな話をいきなり私のところに来てするんですか？","ENG":"But why are you suddenly telling me this?","TWN":"不過你為何要突然跑來跟我說這些呢？"},"stage":{"bg":"MS_1001","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"간단합니다. 당신에게는 제 이야기를 들을 자격이 있기 때문이죠.","JPN":"理由は簡単です。あなたには私の話を聞く資格があるからです。","ENG":"Simple. Because you are worthy of hearing it.","TWN":"理由很簡單，因為你有資格聽我說這些。"},"stage":{"bg":"MS_1001","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"……저기, 학생. 포교인지 뭔지 모르겠지만, 아무튼 저는 관심없어요.","JPN":"……あのね。布教だか何だかわかりませんけど、とにかく私は興味ありませんから。","ENG":"...Look, kid. Whatever you have to say, I'm not interested. All right?","TWN":"……我說，這位同學，我不管你是要跟我傳教還是幹嘛，總之我沒興趣。"},"stage":{"bg":"MS_1001","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그렇겠죠. 당신에겐 이런 뜬구름 잡는 이야기보다 더 소중한 가족이 있으니까요.","JPN":"そうでしょうね。あなたにはこのようなつかみどころのない話よりももっと大切な家族がいるのですから。","ENG":"Just as I expected. You put your family first before some absurd story, do you not?","TWN":"那是當然，對你來說，你的家人比這些摸不著頭緒的話來得更重要吧。"},"stage":{"bg":"MS_1001","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"마침 가족 분들이 오실 시간이군요.","JPN":"ちょうどご家族の皆さんが来る時間ですね。","ENG":"I see your family is right on time to see you.","TWN":"正好你的家人就快來囉。"},"stage":{"bg":"MS_1002","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"강력계라는 직업 때문에 성격이 거치신 건 이해하지만, 따님들 앞에서 아내 분께 너무 화내지 마세요.","JPN":"刑事という職業柄、性格が荒いのは理解できますが、娘さんたちの前で奥さんを叱るのは控えた方がいいですよ。","ENG":"I understand that you get hot-headed due to your job in charge of violent crimes. But please do not lash out on your wife in front of your daughters.","TWN":"我明白你的職業是刑警，性格上比較粗枝大葉一點，但也別在女兒們面前對太太那麼兇。"},"stage":{"bg":"MS_1002","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"잠깐, 보자보자 하니까 당신 대체 뭐야? 우리 딸들은 어떻게 알고!","JPN":"あんた、黙って聞いてればいったい何者なんだ？　うちの娘たちをなんで知ってる！","ENG":"Wait a minute...! Who the hell are you, huh?! How do you know about my daughters?!","TWN":"喂，你不要太過分喔，你到底是誰？怎麼會認識我女兒！"},"stage":{"bg":"MS_1002","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WOMAN_EP9HALF_NULL_NULL","text":{"KOREA":"어머? 여보, 밖에 나와 있었어요?","JPN":"あら？　あなた、外に出てたの？","ENG":"Hmm? Honey, what are you doing out in the cold?","TWN":"嗯？老公，你怎麼會出來？"},"stage":{"bg":"MS_1002","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OSISTER_EP9HALF_NULL_NULL","text":{"KOREA":"차에 있지. 애들 보라고 만든 영화인데 엄청 길더라.","JPN":"車で待ってたらよかったのに。子ども向けの映画なのにやたら長くてさ。","ENG":"Why didn't you stay in the car? This film was far too long, even for a kid's movie.","TWN":"怎麼不待在車裡，說是給兒童看的電影，片長還真長。"},"stage":{"bg":"MS_1002","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YSISTER_EP9HALF_NULL_NULL","text":{"KOREA":"아빠! 이것 봐, 새로 나온 브레멘 전대 인형이다?","JPN":"お父さん！　これ見て、新しいブレーメン戦隊の人形だよ！","ENG":"Daddy! Look at this! It's the new Town Soldiers of Bremen doll!","TWN":"爸爸！你看，是布萊梅戰隊新出的娃娃欸！"},"stage":{"bg":"MS_1002","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};